const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const body = $input.item.json.body || {};
return { json: { token, persona_key: body.persona_key || null, persona_id: body.persona_id || null, topic: body.topic || null, brief: body.brief || null, track: body.track || 'broker', niche_override: body.niche_override || null, source_lead_id: body.source_lead_id || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) && rows[0] ? rows[0] : null;
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
const role = row.user_role;
if (role !== 'admin' && role !== 'client' && role !== 'team_member') return { json: { ok: false, status: 403, error: 'Insufficient role' } };
if ((role === 'client' || role === 'team_member') && !row.client_id) return { json: { ok: false, status: 403, error: 'No client mapped to session' } };
return { json: { ok: true, scope: role === 'admin' ? 'admin' : 'client', client_id: row.client_id || null } };

// Persona resolution + scope check.
// Cross-tenant guard: a client session may only use a persona whose
// client_id matches their session's client_id. Internal personas
// (client_id IS NULL) require admin scope.
const rows = $input.item.json;
const persona = Array.isArray(rows) && rows[0] ? rows[0] : null;
if (!persona) return { json: { ok: false, status: 404, error: 'Persona not found' } };
if (!persona.active) return { json: { ok: false, status: 410, error: 'Persona inactive' } };
if (!persona.tavus_replica_id) return { json: { ok: false, status: 412, error: 'Persona has no Tavus replica configured. See docs/architecture/phase-2a/03-tavus-integration-plan.md' } };

const auth = $('Check Role').first().json;
if (auth.scope === 'client') {
  if (persona.client_id !== auth.client_id) return { json: { ok: false, status: 403, error: 'Cross-tenant access denied' } };
} else if (auth.scope === 'admin') {
  // admin may use any persona; no additional check
}

const req = $('Extract Token + Body').first().json;
return { json: { ok: true, persona, request: req, auth } };

// Compose Anthropic prompt — STUB.
// Real implementation: call Anthropic via httpRequest with
//   system = persona.prompt_framing + niche_overlay.video_script_template
//   user   = topic + brief + (lead context if source_lead_id set)
//   model  = claude-opus-4-7
//   prompt caching enabled on system blocks
// For Phase 2a scaffolding this node is a placeholder that emits
// a script-shaped object so the downstream Tavus call can be wired
// without live API consumption during stub testing.
const data = $input.item.json;
const req = data.request;
const persona = data.persona;
const stubScript = `[STUB SCRIPT — Anthropic node not yet wired]\nPersona: ${persona.persona_key}\nTopic: ${req.topic}\nBrief: ${req.brief || '(none)'}\nNiche: ${req.niche_override || persona.niche_overlay_default || '(persona default)'}\n— Replace this node with Anthropic httpRequest before activation —`;
return { json: { ...data, script: stubScript, script_model: 'stub-not-wired' } };

// Submit Tavus job — STUB.
// Real implementation: POST https://tavusapi.com/v2/videos with
//   replica_id, script, video_name. Tavus credential 'Tavus Crystallux'
//   (Header Auth, x-api-key) must be created before activation.
// For scaffolding this node fakes a tavus_request_id so the
// downstream UPDATE proves the schema works end-to-end.
const piece = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;
const stubReqId = 'stub_' + (piece.id || 'unknown') + '_' + Date.now();
return { json: { ...piece, tavus_request_id: stubReqId } };

// Stripe Meter Hook — STUBBED for Phase 2a.
// Phase 2c: emit Stripe usage event when persona.client_id IS NOT NULL.
// For now: write a placeholder persona_usage_log row with estimated minutes.
// (Estimate is reconciled to actual when polling sees status=ready.)
const piece = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;
return { json: { ...piece, _stripe_meter_stub: 'phase_2c_pending' } };
